@module sampleRender  src=sampleRender.lua  loc=625  sha=217c1f8  mode=chunk  self=sr
@deps cm, ds, cmgr, chrome, gui, sv

# Invariants & contracts
  @invariant  render + input only — handed sv only, never sm; slot mutations route through sv  @ 3
  @invariant  only frame-local caches + ephemeral drag/preview/rename state live here  @ 4
  @invariant  slot index space is linear 0..N_SLOTS-1 (N_SLOTS=64); the slot grid is a 2-col ImGui table (right-aligned index, stretch label) — no row/col addressing  @ 5
  @invariant  strip coordinates are audio sample-frames (0..frames-1); pixel x is derived only at draw via frameToX, and InputInt round-trips frames directly  @ 6
  @invariant  peakCache/durCache are file-path-keyed and survive across frames; peakCache entries are dropped whenever the requested column count changes (window resize) so a strip never reuses peaks computed at a foreign width  @ 7
  @invariant  browser keyboard shortcuts (browserUp/Preview/Assign, slotNext/Prev) are dispatched only when the sample-scope is active in cmgr; the middle pane disables ImGui nav so its own arrow handling produces a single focus rectangle  @ 8
  @invariant  preview-in-place leaves ds:slotEntries untouched while the JSFX slot is staged  @ 9
  @invariant  sv:syncSlot pushes ds's truth back on revert  @ 10
  @invariant  drag.handle is set on the first active frame (closest of start/end to the mouse wins) and held until the button releases — the choice does not switch mid-drag  @ 11
  @contract  samplePage (the controller) owns the stack (sm/sv) and hands this renderer sv only  @ 12
  @contract  left=chrome.gridWidth(w): browser row over a strip, both width gridW  @ 445
  @contract  slots fill chrome.palettePane (full height) on the right  @ 446
  @contract  1px painter dividers: tree|files, browser|strip  @ 447
  @contract  verticals stop GAP/2 short of the horizontal rule; strip bottom-pad clears status bar  @ 448
  @contract  whole body is wrapped in chrome.disabledIf(not isLive) — when the bound track has no live sampler FX the entire interactive surface is greyed and inert  @ 449
  @contract  pip auto-revert is checked at end of body: justTriggered=true edge consumes the trigger frame, after which any browser/slot-focus change or stray mouse click reverts  @ 450

# Shapes
  @shape  peakCacheEntry = { src?=PCM_Source, cols=int, fs=number, nch=int, frames=int, lenSec=number, building=bool, amps?={number,...} } | false  @ 31
  @shape  durCacheEntry  = number | false  @ 32
  @shape  drag = { handle='start'|'end'|nil, slot=int|nil, startF=int|nil, endF=int|nil }  @ 33
  @shape  pip = { slot=int|nil, track=track|nil, justTriggered=bool, browserAtTrigger=path|nil, slotAtTrigger=int|nil }  @ 38
  @shape  ToolbarSegment = { id, render = fn(), visible? = fn() -> bool }  @ 388

